// Solution
function validatePorts(composeConfig) {
  let services = composeConfig.match(/services:.*?/s)[0].replace("services:", "").replace(/\n/g, "").split("");
  let exposedPorts = composeConfig.match(/expose:.*/s)[0].replace("expose:", "").replace(/\n/g, "").split("");
  let servicePorts = composeConfig.match(/ports:.*/s)[0].replace("ports:", "").replace(/\n/g, "").split(" ");
  let exposedPortSet = new Set(exposedPorts);
  let servicePortSet = new Set();
  for (let i = 0; i < services.length; i++) {
    let servicePortsArray = services[i].split(":");
    let port = servicePortsArray[0];
    servicePortSet.add(port);
    if (exposedPortSet.has(port) && servicePortSet.has(port)) {
      return false;
    }
  }
  return true;
}

module.exports = validatePorts;
